// === Freehandsss V47.22 (2026-07-24 cl-flow 2026-07-24-0213 Phase2 — 同部位畫圖動態扣減) ===
// 2026-05-23: Rebuilt getItemCategory() — previous version had corrupted CJK chars.
// 2026-05-23: Added '配件' branch for W_WOOL (羊毛氈公仔 - 加購).
// 2026-05-27: Added 燈飾 - 加購 to '配件' branch.
//             '配件' items with cost=0 excluded from zeroCostItems warning.
// 2026-06-02: V47.14 — P0 修正：keychainItemCount 改用 SUM(Original_Qty) 件數
//             而非行數（order_items 行數），對齊 Finance Bible P0 規則。
// 2026-06-03: V47.15 — B2 修正：補入吊飾運費扣減（對稱鎖匙扣邏輯）
//             charmItemCount 累加吊飾件數，扣減 = (charmItemCount-1) × $35
// 2026-06-05: V47.16 — Task A：packedItems 補四分量欄位（前端透傳）
//             + 收斂律自我檢查（SUM毛值−扣減≈Total_Cost，誤差>$1則警告）
// 2026-06-05: V47.17 — 收斂律警告降級：從 zeroCostItems（污染 Has_Cost_Error）
//             改為 n8nAdjustmentNotes（純審計記錄），防止混合訂單（P_MAIN+加購）
//             因 W1 免畫圖導致四分量與 products.total_base_cost 不同源而誤觸
//             Telegram「待核算」假警報。
// 2026-06-26: V47.18 — S124 v2 語義確認（純注釋，無功能改動）
// 2026-07-17: V47.19 — 吊飾頸鏈成本補回（Fat Mo 全量成本審計）
// 2026-07-22: V47.20 — 吊飾頸鏈記帳格式對齊鎖匙扣環扣模式（D42）
// 2026-07-24: V47.21 — V2統一SKU支援：qty乘法修正 + 吊飾頸鏈雙重計算修正
// 2026-07-24: V47.22 — cl-flow 2026-07-24-0213 Phase2 核心：V2 SKU「同部位第2件起免畫圖」
//   動態扣減。舊SKU嘅畫圖費本身靜態焗死喺SKU目錄價（單購/加購兩條唔同catalog entry），
//   n8n從無做過呢類扣減；V2 SKU嘅畫圖費固定baked入每件unit_full_cost，需要n8n按
//   position_code（左手/右手/左腳/右腳，由Order_Item_Key後綴_LH/_RH/_LF/_RF推導）分組，
//   同一部位總件數中，第1件外全部豁免畫圖費（鏡像現有keychainShippingDeduction/
//   charmChainSharingDiscount嘅寫法同扣減機制，唔重造轆）。豁免範圍**跨品類**（鎖匙扣+
//   吊飾同部位共享豁免資格，同Dashboard前端calculatePricing()嘅chargedPositions
//   set精神一致——同一部位嘅3D掃描只需一次，唔理呢次係做鎖匙扣定吊飾）。
//   寫入結構化欄位 drawing_waived/drawing_charged_count/cost_model_version（migration
//   0073新欄位，0075已擴充sync_order_to_mirror() RPC 支援），取代純文字n8n_adjustment_notes
//   表達（A1/#2、A1/#4 cl-flow反饋）。僅V2 SKU套用；舊SKU完全唔受影響（drawing_waived/
//   drawing_charged_count/cost_model_version維持NULL，同Phase1前一致）。
// Reference: .fhs/ai/FHS_Finance_Bible.md §3-4, §G2/G3, S124 v2 cl-flow 2026-06-26-0922
// Reference: cl-flow 2026-07-24-0213 Phase0-2，FHS_System_Logic_Overview.md §5.4.6

const parseNode = $('Parse Items & Generate SKU');
const parseNodeItems = parseNode ? parseNode.all() : [];

if (parseNodeItems.length === 0) {
    return [{ json: { Total_Revenue: 0, Total_Cost: 0, Final_Profit: 0, Sub_Items: [],
        Cost_Lookup_Warning: "", Has_Cost_Error: false,
        Handmodel_Cost_Total: 0, Keychain_Cost_Total: 0, Necklace_Cost_Total: 0,
        N8n_Cost_Adjustments: 0, N8n_Adjustment_Notes: [] } }];
}

const firstNodeData = parseNodeItems[0].json || {};
const totalRevenue = Number(firstNodeData.Total_Revenue) || 0;
const rawFormState = firstNodeData.Raw_Form_State || "";

let deposit = 0, balance = 0, additionalFee = 0;
try {
    const triggerNode = $('Receive Dashboard Order');
    const triggerBody = (triggerNode && triggerNode.first()) ? (triggerNode.first().json.body || triggerNode.first().json) : {};
    deposit = Number(triggerBody.Deposit) || 0;
    balance = Number(triggerBody.Balance) || 0;
    additionalFee = Number(triggerBody.Additional_Fee) || 0;
} catch (error) {}

// SKU → item_category (Finance Bible §3, V47.12)
// Values must match Supabase order_items.item_category exactly.
function getItemCategory(sku) {
    if (!sku) return '其他';
    if (sku.includes('羊毛氈') || sku.includes('燈飾')) return '配件';
    if (sku.includes('木框') || sku.includes('玻璃瓶') || sku.includes('立體擺設')) return '立體擺設';
    if (sku.includes('鎖匙扣')) return '金屬鎖匙扣';
    if (sku.includes('吊飾')) return '純銀頸鏈吊飾';
    return '其他';
}

// V47.22: Order_Item_Key 後綴 → position_code（_LH/_RH/_LF/_RF，見n8n item_key既有慣例）
function getPositionCode(itemKey) {
    if (!itemKey) return null;
    const suffix = itemKey.split('_').pop().toUpperCase();
    const map = { LH: '左手', RH: '右手', LF: '左腳', RF: '右腳' };
    return map[suffix] || null;
}

// V47.22: V2 SKU 單件畫圖率（同Phase0/Phase1方程式一致：baby S=60/P=110，adult S=110/P=240）
function getDrawingRateForV2Sku(sku) {
    const isAdult = sku.includes('成人');
    const isSMode = sku.includes('(S)');
    if (isAdult) return isSMode ? 110 : 240;
    return isSMode ? 60 : 110;
}

let totalBaseCost = 0;
let handmodelCostTotal = 0;
let keychainCostTotal = 0;
let necklaceCostTotal = 0;
let packedItems = [];
let keychainItemCount = 0; // P0 修正：累加件數（SUM qty），非行數
let charmItemCount = 0;    // B2：吊飾件數累加（SUM qty）
const zeroCostItems = [];

const items = $input.all();
for (let i = 0; i < parseNodeItems.length; i++) {
    let originalItemData = parseNodeItems[i].json || {};
    let itemData = (items[i] && items[i].json) ? items[i].json : originalItemData;

    const sku = originalItemData.Search_SKU || itemData.Search_SKU || "";
    const itemQty = Number(originalItemData.Original_Qty) || 1;
    const isV2Sku = sku.endsWith("(V2)"); // V47.21

    let itemCost = Number(itemData.Total_Base_Cost) || 0;
    // V47.21: V2統一SKU嘅total_base_cost係「單件價」，舊SKU係「成套總價」（已含item_per_set）
    if (isV2Sku) {
        itemCost = itemCost * itemQty;
    }

    // P0 修正：用 Original_Qty 件數累加，不再用 ++ 行數
    if (sku.includes('鎖匙扣')) {
        keychainItemCount += itemQty;
    }
    // B2：吊飾件數累加（對稱鎖匙扣 P0 修正模式）
    if (sku.includes('吊飾')) {
        charmItemCount += itemQty;
    }

    const itemCategory = getItemCategory(sku);

    // V47.20：吊飾頸鏈成本改為品項層對稱摺入（同鎖匙扣環扣同一手法：鎖匙扣嘅環扣早已含喺
    // products.total_base_cost，唔使呢度再加），每件 $100 × 件數，不再信前端 Chain_Cost
    // pass-through；訂單層改用「共用折扣」扣減，見下方 charmChainSharingDiscount
    // （floor(N/2)×100，與現行 ceil(N/2)×100 加項數學等價）。非吊飾類別（鎖匙扣環扣等）
    // 嘅 Chain_Cost 顯示維持前端 pass-through 不變，唔受本次改動影響。
    // V47.21：V2吊飾SKU嘅total_base_cost（已×qty）本身已經baked咗$100/件頸鏈費（Phase1方程式），
    // 唔可以再加一次，否則雙重計算——只計itemChainCost供顯示/審計，唔加落itemCost。
    let itemChainCost;
    if (itemCategory === '純銀頸鏈吊飾') {
        itemChainCost = 100 * itemQty;
        if (!isV2Sku) {
            itemCost += itemChainCost;
        }
    } else {
        itemChainCost = Number(originalItemData.Chain_Cost) || 0;
    }

    totalBaseCost += itemCost;

    // Zero-cost warning: exclude 配件 (intentional $0 service products like W_WOOL / L_LIGHTS)
    if (itemCost === 0 && sku && sku !== '無商品' && sku.trim() !== '' && itemCategory !== '配件') {
        zeroCostItems.push(sku);
    }

    const itemHandmodelCost = itemCategory === '立體擺設'    ? itemCost : 0;
    const itemKeychainCost  = itemCategory === '金屬鎖匙扣'  ? itemCost : 0;
    const itemNecklaceCost  = itemCategory === '純銀頸鏈吊飾' ? itemCost : 0;

    handmodelCostTotal += itemHandmodelCost;
    keychainCostTotal  += itemKeychainCost;
    necklaceCostTotal  += itemNecklaceCost;

    // V47.22: position_code 供下方 dedup pass 使用，只有 V2 鎖匙扣/吊飾先有意義
    const positionCode = (isV2Sku && (itemCategory === '金屬鎖匙扣' || itemCategory === '純銀頸鏈吊飾'))
        ? getPositionCode(originalItemData.Order_Item_Key)
        : null;

    packedItems.push({
        Product_Record_ID: itemData.id || null,
        Product_Name:      itemData.Product_Name || originalItemData.Search_SKU || "Unknown SKU",
        Total_Base_Cost:   itemCost,
        Quantity:          itemQty,
        Notes:             originalItemData.Item_Notes || "",
        Order_Item_Key:    originalItemData.Order_Item_Key || "",
        Item_Category:     itemCategory,
        Handmodel_Cost:    itemHandmodelCost,
        Keychain_Cost:     itemKeychainCost,
        Necklace_Cost:     itemNecklaceCost,
        // Task A: 四分量（前端 calculatePricing() 算好後透傳，Chain_Cost 例外自 V47.20 起由 n8n 權威覆寫）
        Drawing_Cost:  Number(originalItemData.Drawing_Cost)  || 0,
        Printing_Cost: Number(originalItemData.Printing_Cost) || 0,
        Chain_Cost:    itemChainCost,
        Shipping_Cost: Number(originalItemData.Shipping_Cost) || 0,
        // V47.22: Phase2 結構化欄位（見 migration 0073/0075）
        Position_Code:          positionCode,
        Drawing_Waived:         null,  // 下方dedup pass填值，非V2品項維持null
        Drawing_Charged_Count:  null,
        Cost_Model_Version:     isV2Sku ? 'v2_layered' : null,
        _isV2Sku:               isV2Sku,          // 內部暫存，唔輸出到Supabase（Mirror Prep唔會讀呢個key）
        _sku:                   sku
    });
}

// V47.22: 同部位畫圖動態扣減（鏡像keychainShippingDeduction/charmChainSharingDiscount嘅
// 「訂單層扣減+n8n_adjustment_notes審計」寫法，但呢個係跨品類、按position_code分組）
// 分組規則：同一 position_code（左手/右手/左腳/右腳）之下，V2鎖匙扣+V2吊飾共享「已收畫圖費」
// 資格——同Dashboard前端 calculatePricing() 嘅 chargedPositions Set 精神一致：同部位3D掃描
// 只需一次，唔理呢件係鎖匙扣定吊飾。分組內第1件（按packedItems原始順序）收畫圖費，
// 其餘全部豁免。
const positionGroups = {}; // position_code -> [{ packedIndex, qty, drawingRate }]
packedItems.forEach((item, idx) => {
    if (!item.Position_Code) return;
    if (!positionGroups[item.Position_Code]) positionGroups[item.Position_Code] = [];
    positionGroups[item.Position_Code].push({
        packedIndex: idx,
        qty: item.Quantity,
        drawingRate: getDrawingRateForV2Sku(item._sku)
    });
});

let drawingDedupDeduction = 0;
const drawingDedupDetail = []; // 供 n8n_adjustment_notes 記錄

for (const posCode in positionGroups) {
    const group = positionGroups[posCode];
    let unitsChargedSoFar = 0;
    group.forEach(entry => {
        const chargeThisRow = unitsChargedSoFar === 0 ? Math.min(1, entry.qty) : 0;
        const waivedUnits = entry.qty - chargeThisRow;
        const deduction = waivedUnits * entry.drawingRate;

        const packedItem = packedItems[entry.packedIndex];
        packedItem.Drawing_Charged_Count = chargeThisRow;
        packedItem.Drawing_Waived = waivedUnits > 0;

        if (deduction > 0) {
            drawingDedupDeduction += deduction;
            // 按品類扣返 keychainCostTotal / necklaceCostTotal（唔可以淨扣totalBaseCost,
            // 兩個子總額都要對得上，同現有shipping/chain扣減寫法一致）
            if (packedItem.Item_Category === '金屬鎖匙扣') {
                keychainCostTotal -= deduction;
            } else if (packedItem.Item_Category === '純銀頸鏈吊飾') {
                necklaceCostTotal -= deduction;
            }
            drawingDedupDetail.push({
                position_code: posCode,
                item_key: packedItem.Order_Item_Key,
                waived_units: waivedUnits,
                drawing_rate: entry.drawingRate,
                deduction: deduction
            });
        }
        unitsChargedSoFar += entry.qty;
    });
}
totalBaseCost -= drawingDedupDeduction;

// 清走內部暫存 key，唔輸出俾 Supabase Mirror Prep（避免混入未知欄位）
packedItems.forEach(item => { delete item._isV2Sku; delete item._sku; });

// 鎖匙扣多件運費折扣 — P0 修正版：件數而非行數 (Finance Bible §2.5 + Session 52 P0)
const keychainShippingDeduction = keychainItemCount > 1 ? (keychainItemCount - 1) * 20 : 0;
totalBaseCost     -= keychainShippingDeduction;
keychainCostTotal -= keychainShippingDeduction;

// 吊飾多件運費折扣 — B2 補入：件數而非行數 (Finance Bible §2.5 + Session 56 B2)
const charmShippingDeduction = charmItemCount > 1 ? (charmItemCount - 1) * 35 : 0;
totalBaseCost     -= charmShippingDeduction;
necklaceCostTotal -= charmShippingDeduction;

// 吊飾頸鏈共用折扣 — V47.20：每件已喺上方 per-item loop 對稱計咗 $100（品項層），
// 呢度扣返「同拍檔共用」嘅重複部份。floor(charmItemCount/2) 件因為同另一件共用一條
// 頸鏈而獲豁免 $100。數學等價證明：100×N − floor(N/2)×100 = 100×(N−floor(N/2)) = 100×ceil(N/2)，
// 與 V47.19 舊式 necklaceChainCost=ceil(N/2)×100 加項完全相同，總成本/利潤不變，純記帳格式對齊。
// V47.21 註：此扣減純按charmItemCount（件數）計算，唔區分V2/舊SKU，兩者皆適用不變。
const charmChainSharingDiscount = charmItemCount > 1 ? Math.floor(charmItemCount / 2) * 100 : 0;
totalBaseCost     -= charmChainSharingDiscount;
necklaceCostTotal -= charmChainSharingDiscount;

// V47.17: n8nAdjustmentNotes 移至收斂律檢查之前，使收斂律可推入審計記錄
const n8nAdjustmentNotes = [];
if (keychainShippingDeduction > 0) {
    n8nAdjustmentNotes.push({
        type:                "keychain_shipping_deduction",
        amount:              -keychainShippingDeduction,
        desc:                `${keychainItemCount} 件鎖匙扣同時下單（P0修正：件數非行數），扣減 ${keychainItemCount - 1} 件運費補貼 (每件 $20)`,
        basis:               "Finance Bible §2.5, P0 Session 52",
        keychain_item_count: keychainItemCount
    });
}
if (charmShippingDeduction > 0) {
    n8nAdjustmentNotes.push({
        type:             "charm_shipping_deduction",
        amount:           -charmShippingDeduction,
        desc:             `${charmItemCount} 件吊飾同時下單，扣減 ${charmItemCount - 1} 件運費補貼 (每件 $35)`,
        basis:            "Finance Bible §2.5, B2 Session 56",
        charm_item_count: charmItemCount
    });
}
if (charmChainSharingDiscount > 0) {
    n8nAdjustmentNotes.push({
        type:             "necklace_chain_sharing_discount",
        amount:           -charmChainSharingDiscount,
        desc:             `${charmItemCount} 條吊飾每 2 條共用 1 條頸鏈，${Math.floor(charmItemCount / 2)} 條獲豁免 $100（每件已對稱計 $100，此為共用折扣，非額外收費）`,
        basis:            "Finance Bible §6.1 Clasp_Cost, Product_Cost_Schema_v2.md necklace_chain_cost，2026-07-22 顯示一致性修正（比照鎖匙扣環扣模式，D42）",
        charm_item_count: charmItemCount
    });
}
if (drawingDedupDeduction > 0) {
    n8nAdjustmentNotes.push({
        type:   "drawing_position_dedup_deduction",
        amount: -drawingDedupDeduction,
        desc:   `同部位（跨鎖匙扣/吊飾）第2件起免畫圖費，共 ${drawingDedupDetail.length} 個品項行受惠，合計扣減 $${drawingDedupDeduction}`,
        basis:  "cl-flow 2026-07-24-0213 Phase2，同部位首件收畫圖第2件免（原始2024-09-15設計+S52 Finance Bible），僅V2統一SKU適用",
        detail: drawingDedupDetail
    });
}

// Task A: 收斂律自我檢查（§三-B Q1/Q2）
const _fourColGross = packedItems.reduce((s, i) =>
    s + (i.Drawing_Cost||0) + (i.Printing_Cost||0) + (i.Chain_Cost||0) + (i.Shipping_Cost||0), 0);
const _fourColNet = _fourColGross - keychainShippingDeduction - charmShippingDeduction - charmChainSharingDiscount - drawingDedupDeduction;
const _convergenceDiff = Math.abs(_fourColNet - totalBaseCost);
if (_fourColGross > 0 && _convergenceDiff > 1) {
    n8nAdjustmentNotes.push({
        type:   "convergence_note",
        amount: 0,
        desc:   `四分量毛值${_fourColGross}−扣減${keychainShippingDeduction+charmShippingDeduction+charmChainSharingDiscount+drawingDedupDeduction}=${_fourColNet}，products成本${totalBaseCost}（差${_convergenceDiff.toFixed(2)}，審計用）`,
        basis:  "Task A 收斂律，差值因 W1 免畫圖等不同源屬正常，僅供審計"
    });
}

const n8nCostAdjustments = n8nAdjustmentNotes.reduce((sum, item) => sum + (item.amount || 0), 0);

const finalProfit = totalRevenue - totalBaseCost;
const hasCostError = zeroCostItems.length > 0;
const costLookupWarning = hasCostError
    ? `⚠️ SKU 對不到成本，Total_Cost 可能失真!\n以下項目成本 = $0:\n${zeroCostItems.map(s => `• ${s}`).join('\n')}`
    : "";

return [{
    json: {
        ...firstNodeData,
        Total_Revenue:        totalRevenue,
        Total_Cost:           totalBaseCost,
        Final_Profit:         finalProfit,
        Deposit:              deposit,
        Balance:              balance,
        Additional_Fee:       additionalFee,
        Raw_Form_State:       rawFormState,
        Sub_Items:            packedItems,
        Cost_Lookup_Warning:  costLookupWarning,
        Has_Cost_Error:       hasCostError,
        Handmodel_Cost_Total: handmodelCostTotal,
        Keychain_Cost_Total:  keychainCostTotal,
        Necklace_Cost_Total:  necklaceCostTotal,
        N8n_Cost_Adjustments: n8nCostAdjustments,
        N8n_Adjustment_Notes: n8nAdjustmentNotes
    }
}];
